module RefModule(input[4:0] in, input clk, rst, writeData, output[4:0] out);reg [4:0] obf_outData;
	assign out = obf_outData;
	always@(posedge clk, posedge rst)begin
		if(rst) obf_outData <= 5'b0;
		else
		begin
			if(writeData) obf_outData <= in;
			else obf_outData <= obf_outData;
		end
	end
endmodule
